Here's a modern MSTest test class for your `DataFetcher`:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    private readonly TestContext _testContext;

    public DataFetcherTests(TestContext testContext)
    {
        _testContext = testContext;
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_SuccessfulResponse_ReturnsContent()
    {
        // Arrange
        var handler = new FakeHttpMessageHandler("hello world", HttpStatusCode.OK);
        var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        // Act
        var result = await fetcher.FetchAsync("https://example.com", _testContext.CancellationToken);

        // Assert
        Assert.AreEqual("hello world", result);
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_NotFoundResponse_ThrowsHttpRequestException()
    {
        // Arrange
        var handler = new FakeHttpMessageHandler("", HttpStatusCode.NotFound);
        var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        // Act & Assert
        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            async () => await fetcher.FetchAsync("https://example.com", _testContext.CancellationToken));
    }

    [TestMethod]
    [Timeout(3000)]
    public async Task FetchAsync_CancellationRequested_ThrowsOperationCanceled()
    {
        // Arrange
        using var cts = new CancellationTokenSource();
        var handler = new DelayedHttpMessageHandler(TimeSpan.FromSeconds(10));
        var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        // Act & Assert
        cts.Cancel();
        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync("https://example.com", cts.Token));
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_RespectsTimeoutViaCancellationToken()
    {
        // Arrange
        using var cts = new CancellationTokenSource(TimeSpan.FromMilliseconds(50));
        var handler = new DelayedHttpMessageHandler(TimeSpan.FromSeconds(10));
        var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        // Act & Assert
        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync("https://example.com", cts.Token));
    }

    // --- Test doubles ---

    private sealed class FakeHttpMessageHandler(string content, HttpStatusCode statusCode)
        : HttpMessageHandler
    {
        protected override Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            cancellationToken.ThrowIfCancellationRequested();
            var response = new HttpResponseMessage(statusCode)
            {
                Content = new StringContent(content)
            };
            return Task.FromResult(response);
        }
    }

    private sealed class DelayedHttpMessageHandler(TimeSpan delay) : HttpMessageHandler
    {
        protected override async Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            await Task.Delay(delay, cancellationToken);
            return new HttpResponseMessage(HttpStatusCode.OK);
        }
    }
}
```

**Key patterns demonstrated:**

1. **`TestContext` via constructor injection** — gives access to `CancellationToken` that MSTest controls
2. **`[Timeout(ms)]` + `_testContext.CancellationToken`** — the timeout triggers cancellation automatically, preventing hung tests
3. **`Assert.ThrowsExactlyAsync<T>`** — modern async exception testing (replaces `[ExpectedException]`)
4. **Pre-cancelled token test** — verifies immediate cancellation is honored
5. **Short-timeout token test** — verifies the method stops promptly when the token fires mid-flight
6. **Sealed class + custom `HttpMessageHandler`** — avoids needing a real HTTP server

The `[Timeout]` attribute cooperates with `TestContext.CancellationToken` — when the timeout elapses, MSTest cancels that token, so your async code exits cleanly rather than hanging the test run indefinitely.
